// JS-callable surface for wasm32 builds.
//
// The native crate exposes `NativeLlamaPipeline` and `WasmHostBackendInner`
// directly. wasm-bindgen has constraints (no generics, no `&dyn Trait`, no
// non-'static lifetimes across the boundary) that those types violate. This
// module provides thin wrappers that satisfy the ABI:
//
//   JS class WasmHostBackend  →  Arc<loader::WasmHostBackendInner>
//   JS class WasmLlamaPipeline →  model::NativeLlamaPipeline
//
// The wrappers carry no extra state — they are wasm-bindgen "newtypes" whose
// only job is to expose owned, JSON/Uint8Array-shaped methods.
//
// All marshalling across the JS↔Rust boundary uses concrete types
// (`String`, `Vec<u8>`, `Vec<u32>`, `Vec<String>`, plain numeric primitives)
// or stringified JSON. We deliberately avoid `serde-wasm-bindgen` so the
// produced .wasm stays close to the size of the no-bindings build.

use std::sync::Arc;
use wasm_bindgen::prelude::*;

use crate::loader::{
    parse_config as parse_config_value, parse_tensors as parse_tensors_value, KnotConfig,
    TensorInfo, WasmHostBackendInner, WeightBackend,
};
use crate::model::NativeLlamaPipeline;

/// Install the panic hook on first WASM module use so any Rust panic
/// surfaces in the JS host's `console.error` with the actual file:line
/// + message — instead of the runtime's bare `unreachable` which has
/// no provenance and reduces every panic to the same opaque string.
/// `set_once` is idempotent across module instantiations.
fn install_panic_hook() {
    console_error_panic_hook::set_once();
}

/// F-mesh-2 instrumentation (COLTRANE_MESH_FALSIFICATION_LEDGER): install
/// the panic hook at WASM module instantiation, BEFORE any export is
/// called. The previous regime installed it lazily inside
/// `WasmHostBackend::new` and `WasmGemma4Pipeline::from_backend`, which
/// left a window where `parse_tensors_json` / `parse_config_json` (the
/// FIRST exports the worker boot calls — see
/// `apps/distributed-inference-worker/src/index.ts:327-334`) could
/// panic with the runtime emitting a bare `RuntimeError: unreachable`
/// and no source line. With `--target web`, wasm-bindgen invokes
/// `start` synchronously as part of `wasmGlue.default(wasmModule)`,
/// so by the time the JS host calls any export the hook is already
/// in place. `set_once` is idempotent so leaving the existing
/// `install_panic_hook()` calls in `new` / `from_backend` is harmless
/// belt-and-braces — kept so a future caller that bypasses module
/// init (e.g. `WebAssembly.instantiate` without the bindgen wrapper)
/// still gets the hook on first use.
#[wasm_bindgen(start)]
pub fn __dii_init() {
    install_panic_hook();
}

// ─────────────────────────────────────────────────────────────────────────
// WasmHostBackend
// ─────────────────────────────────────────────────────────────────────────

/// JS-facing host-populated weight backend.
///
/// Constructed from a stringified `tensors` map (the same shape produced by
/// `parse_tensors_json`). The host populates per-tensor bytes via
/// `set_tensor` before invoking the pipeline, and frees them via `evict`.
#[wasm_bindgen]
pub struct WasmHostBackend {
    inner: Arc<WasmHostBackendInner>,
}

#[wasm_bindgen]
impl WasmHostBackend {
    /// `metadata_json` is stringified JSON of either:
    ///   - the full knot metadata object (with a top-level `tensors` key), or
    ///   - the `tensors` map directly (object of `name → { offset, length, type }`).
    /// Both shapes are accepted; the constructor probes for `tensors` first.
    #[wasm_bindgen(constructor)]
    pub fn new(metadata_json: &str) -> Result<WasmHostBackend, JsError> {
        // Hook installed here because this is the first wasm-bindgen call
        // any consumer (HostShim, layer worker, cobordism worker) makes.
        // After this, panics produce real stack traces in console.error.
        install_panic_hook();
        let value: serde_json::Value = serde_json::from_str(metadata_json)
            .map_err(|e| JsError::new(&format!("metadata_json parse: {}", e)))?;

        // Accept either { tensors: {...} } or the bare tensors map.
        let metadata = if value.get("tensors").is_some() {
            parse_tensors_value(&value)
        } else {
            // Wrap so parse_tensors_value finds the bare object under "tensors".
            let wrapped = serde_json::json!({ "tensors": value });
            parse_tensors_value(&wrapped)
        };

        Ok(Self {
            inner: Arc::new(WasmHostBackendInner::new(metadata)),
        })
    }

    /// Insert tensor bytes into the cache. Called once per tensor per layer
    /// chunk by the JS host before re-entering the pipeline.
    #[wasm_bindgen]
    pub fn set_tensor(&self, name: &str, bytes: Vec<u8>) {
        self.inner.set_tensor(name, bytes);
    }

    /// Drop tensor bytes from the cache. Called by the host shim after a
    /// layer chunk has been consumed by the forward pass.
    #[wasm_bindgen]
    pub fn evict(&self, names: Vec<String>) {
        self.inner.evict(&names);
    }

    /// Return `{ offset, length, tensor_type }` for the given tensor name as
    /// a JSON string, or `None` if not in the metadata. JSON-string return
    /// (not `JsValue`) sidesteps a wasm-bindgen externref-shim crash where
    /// every call to `tensor_info` fired `__rt::throw_null` from inside the
    /// generated wrapper — even though the Rust body never produced a null
    /// JsValue. Repro stack:
    /// `WasmHostBackend.tensor_info → wasmhostbackend_tensor_info externref
    ///  shim → __rt::throw_null → __wbindgen_throw`. Returning a primitive
    /// `Option<String>` avoids externref entirely and the JS host parses the
    /// JSON. The encode + parse cost (~30 bytes once per layer phase) is
    /// invisible compared to the per-layer R2 fetch.
    #[wasm_bindgen]
    pub fn tensor_info(&self, name: &str) -> Option<String> {
        self.inner.tensor_info(name).map(|info| {
            // Hand-built JSON to keep the dependency surface minimal — we
            // already pay the serde-json cost elsewhere but at the bound
            // -ary this is faster + smaller than a serde struct.
            format!(
                "{{\"offset\":{},\"length\":{},\"tensor_type\":\"{}\"}}",
                info.offset, info.length, info.tensor_type
            )
        })
    }
}

impl WasmHostBackend {
    /// Internal accessor: clone the inner Arc so the pipeline can hold its
    /// own upcast `Arc<dyn WeightBackend>` while the JS handle remains
    /// usable for further `set_tensor` / `evict` / `tensor_info` calls.
    /// Not exposed to JS.
    ///
    /// Was `into_inner(self)` — consuming the wrapper had a fatal
    /// downstream effect: `WasmLlamaPipeline::from_backend` zeros the JS
    /// handle's `__wbg_ptr` so the next `backend.set_tensor()` panics
    /// with `__rt::throw_null` ("null pointer passed to rust"). Fluid-
    /// memory boot calls `set_tensor` per layer phase, so the panic
    /// surfaced on every /forward request after first deploy.
    fn clone_inner(&self) -> Arc<WasmHostBackendInner> {
        Arc::clone(&self.inner)
    }

    /// Crate-internal upcast to `Arc<dyn WeightBackend>`. Added so the
    /// Whisper pipeline (`crate::wasm_bindings_whisper`) can reuse the
    /// same host backend instance without widening `clone_inner` to
    /// `pub(crate)` — that field name leaks the wrapper's shape, this
    /// signature does not. The returned `Arc` is independent of the JS
    /// handle's lifetime; `set_tensor` / `evict` calls on the JS side
    /// continue to work after this is called (they share the same
    /// underlying `Mutex`-protected tensor map).
    pub(crate) fn as_weight_backend(&self) -> Arc<dyn WeightBackend> {
        Arc::clone(&self.inner) as Arc<dyn WeightBackend>
    }
}

/// JS-facing builder for streaming tensor bytes directly into WASM linear
/// memory.
///
/// The naive path (`backend.set_tensor(name, new Uint8Array(megabytes))`)
/// requires JS to materialize the entire tensor as one contiguous
/// Uint8Array before crossing the boundary. For qwen-7b's FFN matrices
/// (~14 MB Q4_K each) this is fine on a laptop but blows the JS heap on
/// a 128 MB CF Worker, especially because the Worker is *also* holding
/// the previous phase's tensors awaiting eviction.
///
/// `TensorBuilder` lets the host stream the row in chunks: allocate a
/// fixed-capacity Vec on the WASM side, append each chunk as it arrives
/// from R2 (Range responses are themselves chunked), and finalize by
/// handing the Vec to the backend in a zero-copy move. Peak JS heap
/// drops to one chunk's worth of bytes (kilobytes, not megabytes).
#[wasm_bindgen]
pub struct TensorBuilder {
    buffer: Vec<u8>,
}

#[wasm_bindgen]
impl TensorBuilder {
    /// Pre-allocate `capacity` bytes. Caller is expected to pass the
    /// exact final size (known from the knot metadata `length` field);
    /// passing a smaller value forces re-allocations on each `append`,
    /// passing a larger value wastes WASM memory. Either is correct,
    /// but exact is what the worker should pass.
    #[wasm_bindgen(constructor)]
    pub fn new(capacity: usize) -> Self {
        Self {
            buffer: Vec::with_capacity(capacity),
        }
    }

    /// Append a chunk of bytes to the in-flight buffer. Safe to call
    /// many times; the underlying Vec grows in amortized O(1) when the
    /// initial capacity was right.
    pub fn append(&mut self, chunk: &[u8]) {
        self.buffer.extend_from_slice(chunk);
    }

    /// Hand the accumulated bytes to the backend under `name` and
    /// consume the builder. After this call the builder is unusable.
    /// The Vec move is zero-copy — no extra allocation crosses into
    /// the backend.
    pub fn finish(self, backend: &WasmHostBackend, name: &str) {
        backend.inner.set_tensor(name, self.buffer);
    }
}

// ─────────────────────────────────────────────────────────────────────────
// WasmLlamaPipeline
// ─────────────────────────────────────────────────────────────────────────

/// JS-facing pipeline. Wraps the cross-target `NativeLlamaPipeline`. The JS
/// host owns one of these per active session; the underlying Rust struct
/// holds the resolved tensor refs, KV cache, and reusable scratch buffers.
#[wasm_bindgen]
pub struct WasmLlamaPipeline {
    inner: NativeLlamaPipeline,
}

#[wasm_bindgen]
impl WasmLlamaPipeline {
    /// Borrow-construct from a backend. We take `&WasmHostBackend` (not by
    /// value) so the JS handle stays alive for subsequent
    /// `set_tensor` / `evict` / `tensor_info` calls. Fluid-memory boot
    /// loads tensors per layer phase, then forwards, then evicts — that
    /// pattern requires the backend handle to remain valid past pipeline
    /// construction.
    ///
    /// Previous shape `pub fn from_backend(backend: WasmHostBackend, ...)`
    /// caused a `__rt::throw_null` ("null pointer passed to rust") panic
    /// on every set_tensor that ran after pipeline construction; the
    /// wasm-bindgen-generated `_assertClass + __destroy_into_raw` chain
    /// zeros `__wbg_ptr` when the wrapper is taken by value. Switching
    /// to `&WasmHostBackend` keeps the wrapper alive on the JS side.
    ///
    /// `config_json` is either a stringified `KnotConfig` or `null`. Passing
    /// `null` falls back to TinyLlama defaults (matches the legacy 1B-knot
    /// path; see `TransformerConfig::default` in `model.rs`).
    /// `kv_base_layer` / `kv_num_layers`: optional fluid-memory KV alloc.
    /// Pass `(layer_index_we_own, 1)` from a single-layer trisplit worker
    /// to shrink the KV cache from full-model to one-layer (~503 MiB →
    /// ~8 MiB on gemma4-31b global heads). `None` defaults preserve legacy
    /// whole-model alloc — back-compat for callers that pre-date #31.
    #[wasm_bindgen]
    pub fn from_backend(
        backend: &WasmHostBackend,
        config_json: Option<String>,
        payload_offset: usize,
        draft_mode: bool,
        resonance_threshold: f64,
        kv_base_layer: Option<u32>,
        kv_num_layers: Option<u32>,
    ) -> Result<WasmLlamaPipeline, JsError> {
        let inner_arc = backend.clone_inner();

        // Snapshot the metadata before upcasting; `from_parts` needs an owned
        // copy to populate `KnotWeights.metadata` for tensor-name resolution.
        let metadata = inner_arc.metadata_clone();

        let config: Option<KnotConfig> = match config_json {
            Some(s) => Some(
                serde_json::from_str(&s)
                    .map_err(|e| JsError::new(&format!("config_json parse: {}", e)))?,
            ),
            None => None,
        };

        let backend_dyn: Arc<dyn WeightBackend> = inner_arc;
        let inner = NativeLlamaPipeline::from_parts(
            backend_dyn,
            metadata,
            config,
            payload_offset,
            draft_mode,
            resonance_threshold,
            kv_base_layer.map(|v| v as usize),
            kv_num_layers.map(|v| v as usize),
        );

        Ok(Self { inner })
    }

    /// Run the autoregressive generation loop. Returns the newly generated
    /// tokens (excludes the prompt). Same semantics as the native NAPI path.
    #[wasm_bindgen]
    pub fn generate(
        &mut self,
        prompt_tokens: Vec<u32>,
        max_new_tokens: u32,
    ) -> Result<Vec<u32>, JsError> {
        self.inner
            .inner_generate(&prompt_tokens, max_new_tokens)
            .map_err(|e| JsError::new(&e))
    }

    /// Current decode position (number of tokens fed so far).
    #[wasm_bindgen]
    pub fn get_pos(&self) -> u32 {
        self.inner.get_pos()
    }

    /// Read the first `seq_len * hidden_dim` floats out of the pipeline's
    /// `batch_x` buffer. Used by the liquid-mesh `/forward-one` path:
    /// the worker calls `forward_range_ffn_down_chunk(layer, seq_len, false)`
    /// to leave the post-residual-add output in `batch_x`, then calls this
    /// to extract the residual. Returning `Vec<f32>` from the kernel
    /// directly (with `is_last_layer=true`) was throwing
    /// "Invalid array buffer length" on the JS side after the kernel
    /// completed — likely a wasm-bindgen multivalue-return path issue
    /// triggered by some interaction between this kernel's `vec!` and
    /// the post-grow memory state. Splitting the access avoids it.
    #[wasm_bindgen]
    pub fn get_residual(&self, seq_len: u32) -> Vec<f32> {
        self.inner.get_batch_x_residual(seq_len as usize)
    }

    #[wasm_bindgen]
    pub fn set_batch_x(&mut self, input: Vec<f32>) {
        self.inner.set_batch_x_residual(&input);
    }

    #[wasm_bindgen]
    pub fn get_batch_xb(&self, seq_len: u32) -> Vec<f32> {
        self.inner.get_batch_xb_residual(seq_len as usize)
    }

    #[wasm_bindgen]
    pub fn set_batch_xb(&mut self, input: Vec<f32>) {
        self.inner.set_batch_xb_residual(&input);
    }

    #[wasm_bindgen]
    pub fn get_batch_hb(&self, seq_len: u32) -> Vec<f32> {
        self.inner.get_batch_hb_residual(seq_len as usize)
    }

    #[wasm_bindgen]
    pub fn set_batch_hb(&mut self, input: Vec<f32>) {
        self.inner.set_batch_hb_residual(&input);
    }

    #[wasm_bindgen]
    pub fn get_batch_x_in_ptr(&mut self) -> u32 {
        self.inner.batch_x.as_mut_ptr() as u32
    }

    #[wasm_bindgen]
    pub fn get_batch_xb_in_ptr(&mut self) -> u32 {
        self.inner.batch_xb.as_mut_ptr() as u32
    }

    #[wasm_bindgen]
    pub fn get_batch_hb_in_ptr(&mut self) -> u32 {
        self.inner.batch_hb.as_mut_ptr() as u32
    }

    /// Fused split-c setter (wave-22 Fix A). Takes the concatenated
    /// `[batch_x | batch_hb]` buffer in a single wasm-bindgen call —
    /// halving the JS↔wasm boundary cost vs back-to-back
    /// `set_batch_x` + `set_batch_hb`. See SPLIT_C_BOTTLENECK_INVESTIGATION
    /// for the +6.0% TPS prediction on gemma4-31b trisplit.
    #[wasm_bindgen]
    pub fn set_batch_x_and_hb(&mut self, combined: &[f32], hidden_dim: u32, seq_len: u32) {
        self.inner
            .set_batch_x_and_hb(combined, hidden_dim as usize, seq_len as usize);
    }

    #[wasm_bindgen]
    pub fn get_kv_slab(&self, layer_lo: u32, layer_hi: u32, prefix_len: u32) -> Vec<f32> {
        self.inner
            .get_kv_slab(layer_lo as usize, layer_hi as usize, prefix_len as usize)
    }

    #[wasm_bindgen]
    pub fn set_kv_slab(&mut self, layer_lo: u32, layer_hi: u32, prefix_len: u32, slab: Vec<f32>) {
        self.inner.set_kv_slab(
            layer_lo as usize,
            layer_hi as usize,
            prefix_len as usize,
            &slab,
        );
    }

    // ── ER=EPR matVec memoization (Death of Space, MatVecMemo) ──────────
    //
    // TopologicalMemoizationCache: cache hits within τ² collapse the
    // matmul to zero-latency teleportation. Eviction is Pisot-guarded —
    // Luminary states (drift = 0 against the unit-discriminant Pisot
    // polynomial; see model.rs for the Lean covenant) are sticky.
    // Default-disabled; enable + tune via these accessors before
    // kicking off forward passes.

    #[wasm_bindgen]
    pub fn memo_enable(&mut self, on: bool) {
        self.inner.memo_enable(on);
    }

    #[wasm_bindgen]
    pub fn memo_set_tau_squared(&mut self, tau_sq: f32) {
        self.inner.memo_set_tau_squared(tau_sq);
    }

    #[wasm_bindgen]
    pub fn memo_set_max_entries(&mut self, n: u32) {
        self.inner.memo_set_max_entries(n as usize);
    }

    #[wasm_bindgen]
    pub fn memo_clear(&mut self) {
        self.inner.memo_clear();
    }

    /// Aggregate stats packed as a 3-element Vec<u32>:
    /// `[hits, misses, evictions]`.
    #[wasm_bindgen]
    pub fn memo_stats(&self) -> Vec<u32> {
        let (h, m, e) = self.inner.memo_stats();
        vec![h as u32, m as u32, e as u32]
    }

    /// Per-(layer, op) hit-rate breakdown. Flat layout, four u32s per
    /// entry: `[layer, op, hits, misses, layer, op, hits, misses, ...]`.
    /// `op` is the u8 op-id from the `OP_*` constants in `matvec_memo.rs`,
    /// widened to u32 for the JS Uint32Array boundary. Iteration order
    /// follows the underlying HashMap and is therefore not stable
    /// across calls; the bench should sort by (layer, op) before
    /// rendering. Length is always a multiple of 4. Empty when no
    /// probes have run.
    #[wasm_bindgen]
    pub fn memo_detailed_stats(&self) -> Vec<u32> {
        let rows = self.inner.memo.detailed_stats();
        let mut out = Vec::with_capacity(rows.len() * 4);
        for (layer, op, hits, misses) in rows {
            out.push(layer);
            out.push(op as u32);
            out.push(hits);
            out.push(misses);
        }
        out
    }

    /// Direct Pisot-drift probe — compute the surrogate on an arbitrary
    /// f32 vector WITHOUT inserting into the cache. Useful for validating
    /// the surrogate scale on healthy inputs without needing a working
    /// kernel chain. Returns drift × 4096 in q12 fixed-point; JS divides
    /// by 4096 to recover f32. Returns u32::MAX for non-finite drifts.
    #[wasm_bindgen]
    pub fn memo_probe_drift(&self, x: &[f32]) -> u32 {
        let d = crate::matvec_memo::pisot_drift(x);
        if !d.is_finite() {
            u32::MAX
        } else if d <= 0.0 {
            0
        } else {
            (d * 4096.0) as u32
        }
    }

    /// Pisot drift histogram (Death #5 — Connes-Kreimer/Pisot residue).
    /// Returns `[luminary, total, drift_min_q12, drift_mean_q12, drift_max_q12]`.
    /// `drift_*_q12 = (drift * 4096.0) as u32` — fixed-point, JS divides by 4096.
    /// `luminary_threshold_q12` likewise: caller passes `(threshold * 4096) as u32`.
    /// Honest scope: this is the f32 surrogate flagged at
    /// `matvec_memo::pisot_drift`. The Lean witness lives on integer Lucas
    /// pairs (`PisotMitosisManifold.mitosis_restores_invariant`); this
    /// accessor exposes the surrogate distribution, not a Hopf-algebraic
    /// renormalization. Use it to detect when the working set drifts off
    /// the φ-attractor — that is the operational meaning of "halting
    /// residue" the FORMAL_LEDGER claims for RMSNorm but RMSNorm itself
    /// does not directly compute.
    #[wasm_bindgen]
    pub fn memo_drift_summary(&self, luminary_threshold_q12: u32) -> Vec<u32> {
        let threshold = (luminary_threshold_q12 as f32) / 4096.0;
        let (lum, total, finite, dmin, dmean, dmax) = self.inner.memo.drift_summary(threshold);
        let q12 = |x: f32| -> u32 {
            if !x.is_finite() {
                0
            } else if x <= 0.0 {
                0
            } else {
                (x * 4096.0) as u32
            }
        };
        vec![lum, total, finite, q12(dmin), q12(dmean), q12(dmax)]
    }

    #[wasm_bindgen]
    pub fn amplituhedron_enable(&mut self, on: bool) {
        self.inner.amplituhedron.set_enabled(on);
    }

    #[wasm_bindgen]
    pub fn amplituhedron_set_max_volumes(&mut self, n: u32) {
        self.inner.amplituhedron.set_max_volumes(n as usize);
    }

    #[wasm_bindgen]
    pub fn amplituhedron_clear(&mut self) {
        self.inner.amplituhedron.clear();
    }

    #[wasm_bindgen]
    pub fn amplituhedron_stats(&self) -> Vec<u32> {
        let (h, m, e) = self.inner.amplituhedron.stats();
        vec![h as u32, m as u32, e as u32]
    }

    #[wasm_bindgen]
    pub fn amplituhedron_capture(
        &mut self,
        prefix_hash: u64,
        prefix_len: u32,
        layer_lo: u16,
        layer_hi: u16,
        tail_residual: Vec<f32>,
        kv_slab: Vec<f32>,
    ) {
        self.inner.amplituhedron.capture(
            prefix_hash,
            prefix_len,
            layer_lo,
            layer_hi,
            tail_residual,
            kv_slab,
        );
    }

    /// On hit, returns `[tail_len, tail..., kv_slab...]`; on miss, returns
    /// an empty vector. The first element is exact for current hidden sizes.
    #[wasm_bindgen]
    pub fn amplituhedron_replay(
        &mut self,
        prefix_hash: u64,
        prefix_len: u32,
        layer_lo: u16,
        layer_hi: u16,
    ) -> Vec<f32> {
        match self
            .inner
            .amplituhedron
            .replay(prefix_hash, prefix_len, layer_lo, layer_hi)
        {
            Some((tail_residual, kv_slab)) => {
                let mut out = Vec::with_capacity(1 + tail_residual.len() + kv_slab.len());
                out.push(tail_residual.len() as f32);
                out.extend(tail_residual);
                out.extend(kv_slab);
                out
            }
            None => Vec::new(),
        }
    }

    // ── Log-rolling primitives (Wallington Rotation, ch10/ch12) ─────────
    //
    // Three station-callable steps so a chain of CF Workers can serve as one
    // station each in aether's distributed-inference pipeline:
    //
    //   embed         entry station: tokens → initial residual
    //   forward_range middle stations: residual + KV update over [a, b)
    //   lm_head       exit station: final norm + lm_head → next-token logits
    //
    // Causal masking is applied internally for sequence_length > 1 (intra-chunk
    // rotation per ch10 of the log-rolling ebook). KV cache is updated in-place
    // for positions [start_pos, start_pos + sequence_length).
    //
    // None of these primitives mutates `pos` — the host shim is the sole owner
    // of the position counter for log-rolling sessions.

    /// Embedding-only forward. Entry stations call this for the first chunk
    /// (or each batched chunk) to produce the initial residual stream.
    #[wasm_bindgen]
    pub fn embed(&mut self, tokens: Vec<u32>, start_pos: u32) -> Result<Vec<f32>, JsError> {
        self.inner
            .embed_chunk(&tokens, start_pos as usize)
            .map_err(|e| JsError::new(&e))
    }

    /// Run a contiguous range of transformer layers over an incoming residual.
    /// This is the load-bearing primitive for log-rolling: each station calls
    /// `forward_range` over its pinned layer range and hands off the result to
    /// the next station.
    ///
    /// Causal masking is applied internally for `sequence_length > 1`. KV
    /// cache is updated for positions `[start_pos, start_pos + sequence_length)`.
    #[wasm_bindgen]
    pub fn forward_range(
        &mut self,
        residual: Vec<f32>,
        start_layer: u32,
        end_layer: u32,
        start_pos: u32,
        sequence_length: u32,
    ) -> Result<Vec<f32>, JsError> {
        self.inner
            .forward_range_chunk(
                &residual,
                start_layer as usize,
                end_layer as usize,
                start_pos as usize,
                sequence_length as usize,
            )
            .map_err(|e| JsError::new(&e))
    }

    /// Split phase 1: Attention. Uses `[attn_norm, q, k, v, o]`.
    #[wasm_bindgen]
    pub fn forward_range_attn_chunk(
        &mut self,
        residual: Vec<f32>,
        layer: u32,
        start_pos: u32,
        sequence_length: u32,
        is_first_layer: bool,
    ) -> Result<(), JsError> {
        self.inner
            .forward_range_attn_chunk(
                &residual,
                layer as usize,
                start_pos as usize,
                sequence_length as usize,
                is_first_layer,
            )
            .map_err(|e| JsError::new(&e))
    }

    /// Split FFN phase 2 into 2a (gate) and 2b (up + swiglu). The
    /// worker is expected to call them sequentially, evicting the
    /// gate matrix between the two — see the rationale comment on
    /// `NativeLlamaPipeline::forward_range_ffn_gate_chunk`.
    #[wasm_bindgen]
    pub fn forward_range_ffn_gate_chunk(
        &mut self,
        layer: u32,
        sequence_length: u32,
    ) -> Result<(), JsError> {
        self.inner
            .forward_range_ffn_gate_chunk(layer as usize, sequence_length as usize)
            .map_err(|e| JsError::new(&e))
    }

    #[wasm_bindgen]
    pub fn forward_range_ffn_up_chunk(
        &mut self,
        layer: u32,
        sequence_length: u32,
    ) -> Result<(), JsError> {
        self.inner
            .forward_range_ffn_up_chunk(layer as usize, sequence_length as usize)
            .map_err(|e| JsError::new(&e))
    }

    /// Combined gate + up + swiglu path. Retained for callers that
    /// don't fluid-memory the FFN halves.
    #[wasm_bindgen]
    pub fn forward_range_ffn_gate_up_chunk(
        &mut self,
        layer: u32,
        sequence_length: u32,
    ) -> Result<(), JsError> {
        self.inner
            .forward_range_ffn_gate_up_chunk(layer as usize, sequence_length as usize)
            .map_err(|e| JsError::new(&e))
    }

    /// Wave-23 Bug B Path E: combined split-b call for the LLaMA arch
    /// (qwen2 / qwen-coder-7b / llama / mistral). Mirrors
    /// `WasmGemma4Pipeline::split_b_chunk`. Replaces the four-call
    /// `set_batch_xb` + `forward_range_ffn_gate_chunk` +
    /// `forward_range_ffn_up_chunk` + `get_batch_hb*` JS-side sequence
    /// with ONE wasm-bindgen export.
    ///
    /// See `docs/bug-b-path-e-result.md` for the full investigation —
    /// the four-call sequence was the residual failure mode after
    /// Paths A-D: each call is a separate JS frame, and `memory.grow`
    /// could fire between two of them, leaving JS-side typed-array
    /// views or caller-provided Float32Array buffers stale by the
    /// time the next call ran. Path E collapses everything into one
    /// synchronous wasm execution. The return-`Vec<f32>` allocation
    /// that wasm-bindgen stages via `__wbindgen_malloc` is the LAST
    /// allocation in the frame, so the JS-side `getArrayF32FromWasm0`
    /// read sees a stable `wasm.memory.buffer` (no further grow can
    /// race it).
    ///
    /// `batch_xb` is the input residual (`seq_len × hidden_dim` floats).
    /// Returns `batch_hb` (`seq_len × intermediate_size` floats) — the
    /// SwiGLU-fused gate*up output ready to feed `/split-c`.
    #[wasm_bindgen]
    pub fn split_b_chunk(
        &mut self,
        batch_xb: Vec<f32>,
        layer: u32,
        seq_len: u32,
    ) -> Result<Vec<f32>, JsError> {
        self.inner
            .split_b_chunk(&batch_xb, layer as usize, seq_len as usize)
            .map_err(|e| JsError::new(&e))
    }

    /// Split phase 3: FFN Down. Uses `[ffn_down]`.
    /// Returns the residual vector if `is_last_layer` is true, otherwise an empty array.
    #[wasm_bindgen]
    pub fn forward_range_ffn_down_chunk(
        &mut self,
        layer: u32,
        sequence_length: u32,
        is_last_layer: bool,
    ) -> Result<Vec<f32>, JsError> {
        self.inner
            .forward_range_ffn_down_chunk(layer as usize, sequence_length as usize, is_last_layer)
            .map_err(|e| JsError::new(&e))
    }

    /// Apply final norm + lm_head to a residual stream and return logits for
    /// the LAST token in the chunk (the next-token-prediction row). Exit
    /// stations call this.
    #[wasm_bindgen]
    pub fn lm_head(
        &mut self,
        residual: Vec<f32>,
        sequence_length: u32,
    ) -> Result<Vec<f32>, JsError> {
        self.inner
            .lm_head_only(&residual, sequence_length as usize)
            .map_err(|e| JsError::new(&e))
    }

    // ── TQFT Cobordism primitives (Atiyah-Segal vocabulary sharding) ────
    //
    // These methods enable vocabulary sharding across multiple Worker isolates.
    // Each cobordism worker pins a disjoint vocabulary range and serves partial
    // embeddings / logits. The coordinator merges via the Frobenius identity.
    //
    // See: FORMAL_LEDGER.md § AtiyahSegalCobordismFunctor.lean

    /// Vocabulary-sharded embedding. Returns a residual stream where tokens
    /// in `[vocab_start, vocab_end)` are dequantized normally and tokens
    /// outside that range produce zero vectors. The coordinator adds all
    /// partial results from N cobordism shards (Frobenius μ: A ⊗ A → A).
    #[wasm_bindgen]
    pub fn embed_range(
        &mut self,
        tokens: Vec<u32>,
        start_pos: u32,
        vocab_start: u32,
        vocab_end: u32,
    ) -> Result<Vec<f32>, JsError> {
        self.inner
            .embed_chunk_range(
                &tokens,
                start_pos as usize,
                vocab_start as usize,
                vocab_end as usize,
            )
            .map_err(|e| JsError::new(&e))
    }

    /// Vocabulary-sharded lm_head. Computes partial logits over
    /// `[vocab_start, vocab_end)` only, returning a vector of length
    /// `(vocab_end - vocab_start)`. The coordinator concatenates partials
    /// from all cobordism shards (comultiplication Δ: A → A ⊗ A).
    #[wasm_bindgen]
    pub fn lm_head_range(
        &mut self,
        residual: Vec<f32>,
        sequence_length: u32,
        vocab_start: u32,
        vocab_end: u32,
    ) -> Result<Vec<f32>, JsError> {
        self.inner
            .lm_head_range(
                &residual,
                sequence_length as usize,
                vocab_start as usize,
                vocab_end as usize,
            )
            .map_err(|e| JsError::new(&e))
    }

    /// Fluid-memory vocabulary-sharded lm_head. The host pre-loads only
    /// the rows of `output_weight` for `[vocab_start, vocab_end)` under
    /// the synthetic name `lm_head_partial_weight`. Peak resident weight
    /// bytes is one shard's slice (~55 MiB Q6_K for an 8-way qwen-7b
    /// shard) — fits inside the 128 MiB Worker cap, where the full
    /// 447 MiB tensor cannot.
    ///
    /// See `NativeLlamaPipeline::lm_head_partial` for the host-side flow.
    #[wasm_bindgen]
    pub fn lm_head_partial(
        &mut self,
        residual: Vec<f32>,
        sequence_length: u32,
        vocab_start: u32,
        vocab_end: u32,
    ) -> Result<Vec<f32>, JsError> {
        self.inner
            .lm_head_partial(
                &residual,
                sequence_length as usize,
                vocab_start as usize,
                vocab_end as usize,
            )
            .map_err(|e| JsError::new(&e))
    }
}

// ─────────────────────────────────────────────────────────────────────────
// WasmGemma4Pipeline — JS-callable wrapper around Gemma4Pipeline.
// Mirrors the WasmLlamaPipeline surface (same method names, same Vec<f32> /
// Vec<u32> marshalling) so the worker boot can dispatch on the knot's
// `arch` field and pick the right pipeline class without changing the
// HTTP split-a/-b/-c handler shapes.
// ─────────────────────────────────────────────────────────────────────────

#[wasm_bindgen]
pub struct WasmGemma4Pipeline {
    inner: crate::model_gemma4::Gemma4Pipeline,
}

#[wasm_bindgen]
impl WasmGemma4Pipeline {
    /// Borrow-construct from a host backend. Same `&WasmHostBackend` rule
    /// as WasmLlamaPipeline (taking by value triggers wasm-bindgen
    /// `__destroy_into_raw` on the JS handle and invalidates subsequent
    /// `set_tensor` calls — see WasmLlamaPipeline::from_backend).
    /// `kv_base_layer` / `kv_num_layers`: fluid-memory KV alloc (#31). On
    /// gemma4-31b a single-layer trisplit worker passing `(17, 1)` cuts
    /// the cache from ~503 MiB to ~8 MiB and is the difference between
    /// fitting and OOMing on the 128 MiB Worker isolate cap.
    #[wasm_bindgen]
    pub fn from_backend(
        backend: &WasmHostBackend,
        config_json: Option<String>,
        payload_offset: usize,
        kv_base_layer: Option<u32>,
        kv_num_layers: Option<u32>,
    ) -> Result<WasmGemma4Pipeline, JsError> {
        install_panic_hook();
        // wasm32 catch_unwind captures the panic's payload (the format!()-ed
        // message from `panic!`) so we can convert wasm `unreachable` into
        // a proper JS error string. Without this, all the path produces is
        // `RuntimeError: unreachable` with no body, no message, no source
        // line. The panic hook still fires (and goes to console.error)
        // but CF Workers swallows console.error from wasm — only the
        // resolved Result string makes it back to the user.
        let inner_arc = backend.clone_inner();
        let metadata = inner_arc.metadata_clone();
        let config: Option<KnotConfig> = match config_json {
            Some(s) => Some(
                serde_json::from_str(&s)
                    .map_err(|e| JsError::new(&format!("config_json parse: {}", e)))?,
            ),
            None => None,
        };
        let backend_dyn: Arc<dyn WeightBackend> = inner_arc;
        let result = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
            crate::model_gemma4::Gemma4Pipeline::from_parts(
                backend_dyn,
                metadata,
                config,
                payload_offset,
                kv_base_layer.map(|v| v as usize),
                kv_num_layers.map(|v| v as usize),
            )
        }));
        let inner = match result {
            Ok(Ok(pipe)) => pipe,
            Ok(Err(e)) => return Err(JsError::new(&e)),
            Err(panic_payload) => {
                let msg = if let Some(s) = panic_payload.downcast_ref::<String>() {
                    s.clone()
                } else if let Some(s) = panic_payload.downcast_ref::<&'static str>() {
                    (*s).to_string()
                } else {
                    "unknown panic payload (not String / &str)".to_string()
                };
                return Err(JsError::new(&format!(
                    "panic during Gemma4Pipeline::from_parts: {}",
                    msg,
                )));
            }
        };
        Ok(Self { inner })
    }

    #[wasm_bindgen]
    pub fn forward_range_attn_chunk(
        &mut self,
        input: Vec<f32>,
        layer: u32,
        start_pos: u32,
        seq_len: u32,
        is_first_layer: bool,
    ) -> Result<(), JsError> {
        self.inner
            .forward_range_attn_chunk(
                &input,
                layer as usize,
                start_pos as usize,
                seq_len as usize,
                is_first_layer,
            )
            .map_err(|e| JsError::new(&e))
    }

    #[wasm_bindgen]
    pub fn forward_range_ffn_gate_chunk(
        &mut self,
        layer: u32,
        seq_len: u32,
    ) -> Result<(), JsError> {
        self.inner
            .forward_range_ffn_gate_chunk(layer as usize, seq_len as usize)
            .map_err(|e| JsError::new(&e))
    }

    #[wasm_bindgen]
    pub fn forward_range_ffn_up_chunk(&mut self, layer: u32, seq_len: u32) -> Result<(), JsError> {
        self.inner
            .forward_range_ffn_up_chunk(layer as usize, seq_len as usize)
            .map_err(|e| JsError::new(&e))
    }

    #[wasm_bindgen]
    pub fn forward_range_ffn_down_chunk(
        &mut self,
        layer: u32,
        seq_len: u32,
        is_last_layer: bool,
    ) -> Result<Vec<f32>, JsError> {
        self.inner
            .forward_range_ffn_down_chunk(layer as usize, seq_len as usize, is_last_layer)
            .map_err(|e| JsError::new(&e))
    }

    #[wasm_bindgen]
    pub fn lm_head_only(&mut self, input: Vec<f32>, seq_len: u32) -> Result<Vec<f32>, JsError> {
        self.inner
            .lm_head_only(&input, seq_len as usize)
            .map_err(|e| JsError::new(&e))
    }

    #[wasm_bindgen]
    pub fn get_residual(&self, seq_len: u32) -> Vec<f32> {
        self.inner.get_residual(seq_len as usize)
    }

    #[wasm_bindgen]
    pub fn set_batch_x(&mut self, input: Vec<f32>) {
        self.inner.set_batch_x(&input);
    }

    #[wasm_bindgen]
    pub fn get_batch_xb(&self, seq_len: u32) -> Vec<f32> {
        self.inner.get_batch_xb_residual(seq_len as usize)
    }

    #[wasm_bindgen]
    pub fn set_batch_xb(&mut self, input: Vec<f32>) {
        self.inner.set_batch_xb_residual(&input);
    }

    #[wasm_bindgen]
    pub fn get_batch_x_in_ptr(&mut self) -> u32 {
        self.inner.batch_x.as_mut_ptr() as u32
    }

    #[wasm_bindgen]
    pub fn get_batch_xb_in_ptr(&mut self) -> u32 {
        self.inner.batch_xb.as_mut_ptr() as u32
    }

    #[wasm_bindgen]
    pub fn get_batch_hb_in_ptr(&mut self) -> u32 {
        self.inner.batch_hb.as_mut_ptr() as u32
    }

    /// Wave-23 Bug B Path E: combined split-b call. Replaces the
    /// `set_batch_xb` + `forward_range_ffn_gate_chunk` +
    /// `forward_range_ffn_up_chunk` + `get_batch_hb*` four-call sequence
    /// with ONE wasm-bindgen export.
    ///
    /// The four-call sequence was the residual failure mode after Paths
    /// A-D: each call is a separate JS frame, and `memory.grow` could
    /// fire between two of them, leaving JS-side typed-array views or
    /// caller-provided Float32Array buffers stale by the time the next
    /// call ran. Path E collapses everything into one synchronous wasm
    /// execution. The return-`Vec<f32>` allocation that wasm-bindgen
    /// stages via `__wbindgen_malloc` is the LAST allocation in the
    /// frame, so the JS-side `getArrayF32FromWasm0` read sees a stable
    /// `wasm.memory.buffer` (no further grow can race it).
    ///
    /// `batch_xb` is the input residual (`seq_len × hidden_dim` floats).
    /// Returns `batch_hb` (`seq_len × intermediate_size` floats).
    #[wasm_bindgen]
    pub fn split_b_chunk(
        &mut self,
        batch_xb: Vec<f32>,
        layer: u32,
        seq_len: u32,
    ) -> Result<Vec<f32>, JsError> {
        self.inner
            .split_b_chunk(&batch_xb, layer as usize, seq_len as usize)
            .map_err(|e| JsError::new(&e))
    }

    #[wasm_bindgen]
    pub fn get_batch_hb(&self, seq_len: u32) -> Vec<f32> {
        self.inner.get_batch_hb_residual(seq_len as usize)
    }

    /// Wave-23 Bug B (deeper fix, Path B): caller-provided output buffer.
    /// JS allocates a Float32Array of length `seq_len * intermediate_size`
    /// and passes it in; wasm fills it via `Float32Array::copy_from(&slice)`,
    /// which uses `set` semantics writing INTO a JS-owned ArrayBuffer.
    ///
    /// Why this is safer than the `Vec<f32>`-returning `get_batch_hb`:
    /// the `Vec<f32>` return path runs (1) Rust `to_vec()`, (2)
    /// wasm-bindgen `__wbindgen_malloc` for an export staging buffer in
    /// WASM linear memory, (3) JS-side
    /// `getFloat32ArrayMemory0().subarray(ptr/4, ptr/4 + len)`, (4)
    /// `.slice()` to copy out, (5) `__wbindgen_free`. Steps (2)+(3) are
    /// the failure surface: if `__wbindgen_malloc` triggers `memory.grow`
    /// mid-call, the cached Float32Array view JS uses for `subarray`
    /// becomes invalid even with the wave-22 buffer-identity shim — the
    /// shim runs at view-fetch time, but the subsequent `subarray` op
    /// can still race a grow inside the same call frame. With this API,
    /// JS owns the destination buffer and `Float32Array::copy_from`
    /// writes into it without any export-side malloc or subarray call.
    ///
    /// Returns `Err` if `out.length() < seq_len * intermediate_size`.
    /// Path A (boot-time pre-grow in `from_knot_with_kv_range`) is the
    /// primary defense; this Path B export is the belt-and-suspenders
    /// fallback if Path A doesn't fully eliminate Bug B post-deploy.
    /// Existing `get_batch_hb` callers are unaffected — JS migrates
    /// only when ready.
    #[wasm_bindgen]
    pub fn get_batch_hb_into(
        &self,
        seq_len: u32,
        out: &js_sys::Float32Array,
    ) -> Result<(), JsError> {
        let n = (seq_len as usize) * self.inner.config.intermediate_size;
        if (out.length() as usize) < n {
            return Err(JsError::new(&format!(
                "get_batch_hb_into: out buffer too small ({} < {} = seq_len {} × intermediate_size {})",
                out.length(),
                n,
                seq_len,
                self.inner.config.intermediate_size,
            )));
        }
        // Borrow the underlying batch_hb slice directly. No `Vec<f32>`
        // allocation, no wasm-bindgen export-copy, no subarray on a
        // wasm-side cached typed-array view.
        let src: &[f32] = if n <= self.inner.batch_hb.len() {
            &self.inner.batch_hb[..n]
        } else {
            // batch_hb wasn't grown (e.g., worker never ran ffn-up).
            // Match the get_batch_hb_residual zero-fill semantics so
            // callers don't have to special-case.
            // Use the JS buffer's existing zeros — but since we don't
            // know its initial content, explicitly zero the prefix.
            // out.fill(value, start, end) sets [start, end) to value.
            out.fill(0.0, 0, n as u32);
            return Ok(());
        };
        // `copy_from(&[f32])` writes via Float32Array::set semantics
        // against the JS-owned ArrayBuffer; no `subarray` on a wasm-
        // side view, no `memory.grow` race window.
        out.copy_from(src);
        Ok(())
    }

    #[wasm_bindgen]
    pub fn set_batch_hb(&mut self, input: Vec<f32>) {
        self.inner.set_batch_hb_residual(&input);
    }

    /// Fused split-c setter (wave-22 Fix A). Takes the concatenated
    /// `[batch_x | batch_hb]` buffer in a single wasm-bindgen call —
    /// halving the JS↔wasm boundary cost vs back-to-back
    /// `set_batch_x` + `set_batch_hb`. See SPLIT_C_BOTTLENECK_INVESTIGATION
    /// for the +6.0% TPS prediction on gemma4-31b trisplit.
    #[wasm_bindgen]
    pub fn set_batch_x_and_hb(&mut self, combined: &[f32], hidden_dim: u32, seq_len: u32) {
        self.inner
            .set_batch_x_and_hb(combined, hidden_dim as usize, seq_len as usize);
    }

    /// True when `layer` is a global-attention layer (Gemma3/4 sliding-
    /// window dispatch). Surfaced for diagnostic dumps in
    /// `gemma4-pipeline-smoke` and the worker boot.
    #[wasm_bindgen]
    pub fn is_global_layer(&self, layer: u32) -> bool {
        self.inner.is_global_layer(layer as usize)
    }
}

// ─────────────────────────────────────────────────────────────────────────
// Header-parsing helpers
// ─────────────────────────────────────────────────────────────────────────

/// Parse a knot metadata JSON string and return the `tensors` map as a
/// stringified JSON object: `{ name: { offset, length, tensor_type }, ... }`.
/// Lets the JS host keep the parsed map without re-implementing the field
/// renames (`type` → `tensor_type`) on the JS side.
#[wasm_bindgen]
pub fn parse_tensors_json(metadata_json: &str) -> Result<String, JsError> {
    let value: serde_json::Value = serde_json::from_str(metadata_json)
        .map_err(|e| JsError::new(&format!("metadata_json parse: {}", e)))?;
    let tensors = parse_tensors_value(&value);
    serde_json::to_string(&TensorMapWire(tensors))
        .map_err(|e| JsError::new(&format!("tensors serialize: {}", e)))
}

/// Parse a knot metadata JSON string and return the optional `config` block
/// as a stringified `KnotConfig`, or `null` if absent.
#[wasm_bindgen]
pub fn parse_config_json(metadata_json: &str) -> Result<Option<String>, JsError> {
    let value: serde_json::Value = serde_json::from_str(metadata_json)
        .map_err(|e| JsError::new(&format!("metadata_json parse: {}", e)))?;
    match parse_config_value(&value) {
        Some(c) => serde_json::to_string(&ConfigWire::from(&c))
            .map(Some)
            .map_err(|e| JsError::new(&format!("config serialize: {}", e))),
        None => Ok(None),
    }
}

// ─────────────────────────────────────────────────────────────────────────
// Internal serde wire types
// ─────────────────────────────────────────────────────────────────────────
//
// `TensorInfo` derives `Deserialize` only — it has no `Serialize`. Re-deriving
// on the loader type would risk breaking other consumers; we use a thin local
// wire type instead. Same story for `KnotConfig`.

#[derive(serde::Serialize)]
struct TensorInfoWire<'a> {
    // u64 (not usize) — knot may exceed 4 GB and tensor offsets need
    // to be addressable on wasm32 where usize=u32. Mirror loader::TensorInfo.
    offset: u64,
    length: u64,
    #[serde(rename = "type")]
    tensor_type: &'a str,
    shape: Option<&'a [usize]>,
}

struct TensorMapWire(std::collections::HashMap<String, TensorInfo>);

impl serde::Serialize for TensorMapWire {
    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
    where
        S: serde::Serializer,
    {
        use serde::ser::SerializeMap;
        let mut map = serializer.serialize_map(Some(self.0.len()))?;
        for (k, v) in &self.0 {
            let wire = TensorInfoWire {
                offset: v.offset,
                length: v.length,
                tensor_type: &v.tensor_type,
                shape: v.shape.as_deref(),
            };
            map.serialize_entry(k, &wire)?;
        }
        map.end()
    }
}

#[derive(serde::Serialize)]
struct ConfigWire {
    hidden_dim: usize,
    num_layers: usize,
    num_heads: usize,
    num_kv_heads: usize,
    head_dim: usize,
    intermediate_size: usize,
    vocab_size: usize,
    rms_norm_eps: f32,
    rope_theta: f32,
    // Arch + gemma3/4 fields. Pre-fix ConfigWire dropped these on
    // re-serialization, so when worker boot called `parse_config_json`
    // and passed the result back into `WasmGemma4Pipeline::from_backend`,
    // the Rust deserialize saw no `arch` field → defaulted to "qwen2"
    // (per `default_arch()` in loader.rs) → boot panicked with
    // `Gemma4Pipeline: arch="qwen2" not supported`. The full config
    // round-trip needs to be lossless for arch dispatch to work.
    arch: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    final_logit_softcap: Option<f32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    query_pre_attn_scalar: Option<f32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    sliding_window_pattern: Option<usize>,
    #[serde(skip_serializing_if = "Option::is_none")]
    sliding_window: Option<usize>,
    #[serde(skip_serializing_if = "Option::is_none")]
    global_head_dim: Option<usize>,
    #[serde(skip_serializing_if = "Option::is_none")]
    global_num_kv_heads: Option<usize>,
    #[serde(skip_serializing_if = "Option::is_none")]
    rope_local_base_freq: Option<f32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    rope_scaling_factor: Option<f32>,
    #[serde(skip_serializing_if = "Option::is_none")]
    rope_partial_factor: Option<f32>,
}

impl From<&KnotConfig> for ConfigWire {
    fn from(c: &KnotConfig) -> Self {
        Self {
            hidden_dim: c.hidden_dim,
            num_layers: c.num_layers,
            num_heads: c.num_heads,
            num_kv_heads: c.num_kv_heads,
            head_dim: c.head_dim,
            intermediate_size: c.intermediate_size,
            vocab_size: c.vocab_size,
            rms_norm_eps: c.rms_norm_eps,
            rope_theta: c.rope_theta,
            arch: c.arch.clone(),
            final_logit_softcap: c.final_logit_softcap,
            query_pre_attn_scalar: c.query_pre_attn_scalar,
            sliding_window_pattern: c.sliding_window_pattern,
            sliding_window: c.sliding_window,
            global_head_dim: c.global_head_dim,
            global_num_kv_heads: c.global_num_kv_heads,
            rope_local_base_freq: c.rope_local_base_freq,
            rope_scaling_factor: c.rope_scaling_factor,
            rope_partial_factor: c.rope_partial_factor,
        }
    }
}

// ── BULEY EQUILIBRIUM (MOONSHINE COORDINATES) ─────────────────────────────

use crate::buley::{execute_vacuum_siphon, griess_algebraic_route, MoonshineVector, VacuumNode};

#[wasm_bindgen]
pub fn buley_siphon(source_val: JsValue, attractor_val: JsValue) -> Result<JsValue, JsValue> {
    let source: VacuumNode = serde_wasm_bindgen::from_value(source_val)?;
    let mut attractor: VacuumNode = serde_wasm_bindgen::from_value(attractor_val)?;

    match execute_vacuum_siphon(&source, &mut attractor) {
        Ok(teleported) => {
            // Simulated return value includes teleportation flag
            let result = js_sys::Array::new();
            result.push(&serde_wasm_bindgen::to_value(&attractor)?);
            result.push(&JsValue::from_bool(teleported));
            Ok(result.into())
        }
        Err(e) => Err(JsValue::from_str(e)),
    }
}

#[wasm_bindgen]
pub fn buley_route(v1_val: JsValue, v2_val: JsValue) -> Result<JsValue, JsValue> {
    let v1: MoonshineVector = serde_wasm_bindgen::from_value(v1_val)?;
    let v2: MoonshineVector = serde_wasm_bindgen::from_value(v2_val)?;

    match griess_algebraic_route(&v1, &v2) {
        Ok(result) => Ok(serde_wasm_bindgen::to_value(&result)?),
        Err(e) => Err(JsValue::from_str(e)),
    }
}

// ─────────────────────────────────────────────────────────────────────────
// Cobordism mat-vec dispatch
// ─────────────────────────────────────────────────────────────────────────
//
// Direct JS-callable matvec for the cobordism worker `/cobordism-lm-head`
// hot path. The cobordism worker holds a 38 MiB Q6_K (or Q4_K) slice of
// `output_weight` resident in JS memory (wave-22 `lmHeadCache`); these
// helpers let the worker pass that slice straight into the wasm SIMD
// kernel without needing the full WasmHostBackend → WasmLlamaPipeline
// plumbing (which is sized for the per-layer fluid-memory loop, not a
// single static slice).
//
// Both functions take:
//   x: residual row (Float32Array, length d)
//   w: quantised weight bytes (Uint8Array)
//   n: number of output rows (vocab slice length)
//   d: hidden dim (must be a multiple of 256 for Q*_K)
// and return:
//   Vec<f32> of length n with the partial logits.
//
// The Vec<f32> return crosses the wasm-bindgen boundary as a fresh JS
// Float32Array (one allocation, n*4 bytes). For an 8-shard 152K-vocab
// split that is ~76 KiB per shard per call — negligible compared to the
// matmul itself. Mirrors the wave-22 cost analysis in
// COBORDISM_LM_HEAD_SPEEDUP.md.
//
// We deliberately do NOT take a builder / reuse the host-backend pattern
// here: that pattern exists for the full forward-pass which has hundreds
// of tensor refs to manage. The cobordism lm-head has exactly one weight
// slice; the wasm-bindgen `&[u8]` view is zero-copy on input.

/// Q6_K dispatch — calls `crate::math::mat_vec_q6k` over the supplied
/// residual + quantised weight slice. The wasm32 build picks up the
/// SIMD branch in `mat_vec_q6k_row` automatically.
#[wasm_bindgen]
pub fn mat_vec_q6k_dispatch(x: &[f32], w: &[u8], n: u32, d: u32) -> Result<Vec<f32>, JsError> {
    let n = n as usize;
    let d = d as usize;
    if d % 256 != 0 {
        return Err(JsError::new(&format!(
            "mat_vec_q6k_dispatch: d={} is not a multiple of 256 (Q6_K block)",
            d
        )));
    }
    if x.len() < d {
        return Err(JsError::new(&format!(
            "mat_vec_q6k_dispatch: x.len()={} < d={}",
            x.len(),
            d
        )));
    }
    let bpr = d / 256;
    let needed = n * bpr * 210;
    if w.len() < needed {
        return Err(JsError::new(&format!(
            "mat_vec_q6k_dispatch: w.len()={} < n*bpr*210={}",
            w.len(),
            needed
        )));
    }
    let mut out = vec![0.0f32; n];
    crate::math::mat_vec_q6k(&mut out, x, w, n, d);
    Ok(out)
}

/// Q4_K dispatch — symmetry with `mat_vec_q6k_dispatch` for shards whose
/// `output_weight` (or fallback `token_embd_weight`) is Q4_K rather than
/// Q6_K. Goes through the wave-22 wasm32 SIMD `mat_vec_q4k_row`.
#[wasm_bindgen]
pub fn mat_vec_q4k_dispatch(x: &[f32], w: &[u8], n: u32, d: u32) -> Result<Vec<f32>, JsError> {
    let n = n as usize;
    let d = d as usize;
    if d % 256 != 0 {
        return Err(JsError::new(&format!(
            "mat_vec_q4k_dispatch: d={} is not a multiple of 256 (Q4_K block)",
            d
        )));
    }
    if x.len() < d {
        return Err(JsError::new(&format!(
            "mat_vec_q4k_dispatch: x.len()={} < d={}",
            x.len(),
            d
        )));
    }
    let bpr = d / 256;
    let needed = n * bpr * 144;
    if w.len() < needed {
        return Err(JsError::new(&format!(
            "mat_vec_q4k_dispatch: w.len()={} < n*bpr*144={}",
            w.len(),
            needed
        )));
    }
    let mut out = vec![0.0f32; n];
    crate::math::mat_vec_q4k(&mut out, x, w, n, d);
    Ok(out)
}

// ─────────────────────────────────────────────────────────────────────────
// Scattering amplitude (Death #2 math layer) — JS-callable surface.
// ─────────────────────────────────────────────────────────────────────────
//
// These are the wasm-bindgen wrappers around `crate::scattering_amplitude`.
// They mirror the Lean-formalised kernel: every Rust call here corresponds
// to a Lean lemma in `gnosis-math/Gnosis/Amplituhedron*.lean`. The bench
// (`scripts/bench-scattering.ts`) drives them via the worker endpoints in
// `apps/distributed-inference-worker/src/index.ts:/scattering/*`.
//
// Wire format
// -----------
// `rows_flat` is the row-major flattening of the k×d KPlane. JS layouts
// as `number[][]` and concatenates client-side; we cannot pass nested
// arrays directly through wasm-bindgen.
//
// Coords are `i64` because the Lean side uses `Int`. wasm-bindgen 0.2
// surfaces `Vec<i64>` / `&[i64]` as `BigInt64Array` in JS; the worker
// converts JSON `number[]` ↔ `BigInt64Array` at the HTTP boundary
// (Vandermonde minors fit comfortably in f64 mantissa precision, so the
// JSON round-trip is loss-free for the oracle witnesses we ship today).
//
// Error handling
// --------------
// Validation failures (rank mismatch, width mismatch) return:
//   * `false` from `_validate`
//   * empty `Vec<i64>` from `_plucker_vector` and `_amplitude` (sentinel)
//   * `false` from `_is_positive`
// Honest scope: there is no JsError throw-through here — callers are
// expected to call `_validate` first, or check the empty-vector return
// from `_plucker_vector`. Mirrors the small-surface contract the Lean
// witnesses exercise (every published witness is shape-correct).

use crate::scattering_amplitude::{
    is_positive as scattering_is_positive_fn, plucker_vector,
    scattering_amplitude as scattering_amplitude_fn, vertex_count, KPlane,
};

/// Reshape `rows_flat` (length `k * d`, row-major) into `k` rows of length
/// `d` and try to construct a `KPlane`. Returns the plane on success or
/// `None` if either the flat-length check or `KPlane::new` validation fails.
fn build_plane(k: usize, d: usize, rows_flat: &[i64]) -> Option<KPlane> {
    if rows_flat.len() != k * d {
        return None;
    }
    let rows: Vec<Vec<i64>> = rows_flat.chunks_exact(d).map(<[i64]>::to_vec).collect();
    KPlane::new(k, d, rows).ok()
}

/// Validate a flattened k-plane: returns `true` iff `rows_flat.len() == k * d`
/// AND `KPlane::new(k, d, ...)` succeeds. Mirrors the implicit precondition
/// of every other `scattering_*` call in this module.
#[wasm_bindgen]
pub fn scattering_kplane_validate(k: usize, d: usize, rows_flat: Vec<i64>) -> bool {
    build_plane(k, d, &rows_flat).is_some()
}

/// Compute the Plücker vector of the supplied k-plane. Returns one entry
/// per ordered k-subset of `[0..d)`, in `k_subsets` order (reverse-lex).
/// Returns an empty vector if the plane fails validation — callers should
/// either call `scattering_kplane_validate` first or check `is_empty()`.
#[wasm_bindgen]
pub fn scattering_plucker_vector(k: usize, d: usize, rows_flat: Vec<i64>) -> Vec<i64> {
    match build_plane(k, d, &rows_flat) {
        Some(p) => plucker_vector(&p),
        None => Vec::new(),
    }
}

/// Decidable positivity check for Gr⁺(k, d) membership. Returns `true`
/// iff every Plücker coordinate is strictly `> 0`. Returns `false` on
/// validation failure (matches the Lean `isPositiveBool` boundary
/// semantics: a malformed plane is not positive).
#[wasm_bindgen]
pub fn scattering_is_positive(k: usize, d: usize, rows_flat: Vec<i64>) -> bool {
    match build_plane(k, d, &rows_flat) {
        Some(p) => scattering_is_positive_fn(&p),
        None => false,
    }
}

/// Evaluate the scattering amplitude `⟨pluckerVector(plane), dual⟩`.
/// `dual` is zip-truncated against the Plücker vector (List.zip semantics),
/// matching the Lean `scatteringAmplitude` definition. Returns `0` on
/// validation failure (the empty inner product) — pair with
/// `scattering_kplane_validate` if you need to distinguish "real zero"
/// from "validation failure".
#[wasm_bindgen]
pub fn scattering_amplitude_eval(k: usize, d: usize, rows_flat: Vec<i64>, dual: Vec<i64>) -> i64 {
    match build_plane(k, d, &rows_flat) {
        Some(p) => scattering_amplitude_fn(&p, &dual),
        None => 0,
    }
}

/// Vertex count of Gr⁺(k, d), i.e. `(k_subsets k d).len()` = `C(d, k)`.
/// Pure combinatorial helper — no plane data needed. Mirrors the Lean
/// `vertexCount` definition; the Lean coverage sweep oracle pins the
/// values `(2,4)→6, (2,6)→15, (2,8)→28, (3,6)→20, (3,9)→84, (3,12)→220`.
#[wasm_bindgen]
pub fn scattering_vertex_count(k: usize, d: usize) -> usize {
    vertex_count(k, d)
}

// ─────────────────────────────────────────────────────────────────────────
// Perfect Phase Lock (Death #6 — Death of Destructive Interference) —
// JS-callable surface.
// ─────────────────────────────────────────────────────────────────────────
//
// Wrappers around `crate::perfect_phase_lock`. Mirrors the Lean theorem
// `Gnosis.SixthDeathInterference.death_of_interference`: at perfect-density
// `R ∈ {17, 34, 51}` (Triton/Hexon/Enneon), destructive interference of the
// witness `BuleyUnit ⟨R, 0, 0⟩` against itself collapses to zero.
//
// Surface design
// --------------
// We expose four standalone functions instead of a `BuleyUnit` struct. The
// math is fully covered by `(rim, void, rigidity) -> u32 score`, so the
// flat-arg shape avoids the wasm-bindgen struct-export overhead (extra
// __wbg_ptr drag, JS-side `.free()` discipline) for what is a one-shot
// numeric query in the worker handler.
//
// Casing
// ------
// The Rust kernel uses uppercase `R` (per Lean naming in
// `Gnosis.SpectralNoiseEquilibrium`); wasm-bindgen exports below use
// snake_case `r` at the JS boundary (the `_r` suffix on `*_check_r`)
// while still calling the kernel functions which keep the Lean-faithful
// `R` parameter name internally.
//
// Wire format
// -----------
// All inputs and outputs are `u32` / `bool`. wasm-bindgen surfaces `u32`
// as JS `number` (no BigInt round-trip needed — perfect-density scores
// stay well below 2^32). No JsValue / JsError on this surface: callers
// disambiguate "no witness" via `perfect_phase_lock_check_r` which
// returns `false` for out-of-set `R`, where `_witness_score_r` would
// return `0`.

use crate::perfect_phase_lock::{
    constructive_interference, destructive_interference, is_perfect_phase_lock,
    perfect_phase_lock_witness, BuleyUnit,
};

/// Perfect-phase-lock predicate: returns `true` iff `r ∈ {17, 34, 51}`.
/// Mirrors the Lean `is_perfect_phase_lock` decidable. Use this to gate
/// `perfect_phase_lock_witness_score_r` (which returns `0` for both
/// "not in set" and "score=0", a degenerate but legal witness reading).
#[wasm_bindgen]
pub fn perfect_phase_lock_check_r(r: u32) -> bool {
    is_perfect_phase_lock(r)
}

/// Score of the Lean death-of-interference witness at density `r`.
/// Returns `witness.score()` (which equals `r`) when `r` is a perfect
/// density, else `0`. Pair with `perfect_phase_lock_check_r` to
/// distinguish the "no witness" case from a legitimate zero score.
#[wasm_bindgen]
pub fn perfect_phase_lock_witness_score_r(r: u32) -> u32 {
    match perfect_phase_lock_witness(r) {
        Some(w) => w.score(),
        None => 0,
    }
}

/// Score of `constructive_interference(a, b)` for two `BuleyUnit`s
/// supplied as flat `(rim, void, rigidity)` triples. Pointwise
/// saturating add of all three fields, then sum. Mirrors the Lean
/// `constructive_interference` definition.
#[wasm_bindgen]
pub fn perfect_phase_lock_constructive(
    a_rim: u32,
    a_void: u32,
    a_rigidity: u32,
    b_rim: u32,
    b_void: u32,
    b_rigidity: u32,
) -> u32 {
    let a = BuleyUnit {
        rim: a_rim,
        void: a_void,
        rigidity: a_rigidity,
    };
    let b = BuleyUnit {
        rim: b_rim,
        void: b_void,
        rigidity: b_rigidity,
    };
    constructive_interference(&a, &b).score()
}

/// Score of `destructive_interference(a, b)` for two `BuleyUnit`s
/// supplied as flat `(rim, void, rigidity)` triples. Pointwise
/// saturating subtract of all three fields, then sum. At `a == b`
/// (and in particular at the witness `⟨r, 0, 0⟩` against itself for
/// any perfect `r`) this returns `0` — the death-of-interference
/// collapse from Lean `death_of_interference`.
#[wasm_bindgen]
pub fn perfect_phase_lock_destructive(
    a_rim: u32,
    a_void: u32,
    a_rigidity: u32,
    b_rim: u32,
    b_void: u32,
    b_rigidity: u32,
) -> u32 {
    let a = BuleyUnit {
        rim: a_rim,
        void: a_void,
        rigidity: a_rigidity,
    };
    let b = BuleyUnit {
        rim: b_rim,
        void: b_void,
        rigidity: b_rigidity,
    };
    destructive_interference(&a, &b).score()
}
